from __future__ import annotations

import math
from decimal import Decimal
from typing import Dict, List, Sequence, Tuple


PI = 3.1415926535


Point = Tuple[float, float]


def realcompare(a: float, b: float) -> str:
    """Compare two reals using six significant digits."""

    def six_sig(value: float) -> Decimal:
        if value == 0.0:
            return Decimal(0)
        return Decimal(format(value, ".6g"))

    left = six_sig(a)
    right = six_sig(b)
    if left < right:
        return "LT"
    if left > right:
        return "GT"
    return "EQ"


def _point(index: int, x: Sequence[float], y: Sequence[float]) -> Point:
    return (x[index], y[index])


def _same_point(p1: Point, p2: Point) -> bool:
    return realcompare(p1[0], p2[0]) == "EQ" and realcompare(p1[1], p2[1]) == "EQ"


def _distance(p1: Point, p2: Point) -> float:
    return math.hypot(p2[0] - p1[0], p2[1] - p1[1])


def _triangle_area(p1: Point, p2: Point, p3: Point) -> float:
    return abs(
        p1[0] * (p2[1] - p3[1])
        + p2[0] * (p3[1] - p1[1])
        + p3[0] * (p1[1] - p2[1])
    ) / 2.0


def _angle(p1: Point, vertex: Point, p3: Point) -> float | None:
    if _same_point(p1, vertex) or _same_point(p3, vertex):
        return None

    v1x = p1[0] - vertex[0]
    v1y = p1[1] - vertex[1]
    v2x = p3[0] - vertex[0]
    v2y = p3[1] - vertex[1]
    mag1 = math.hypot(v1x, v1y)
    mag2 = math.hypot(v2x, v2y)
    cos_theta = (v1x * v2x + v1y * v2y) / (mag1 * mag2)
    cos_theta = max(-1.0, min(1.0, cos_theta))
    return math.acos(cos_theta)


def _distance_from_line(point: Point, line_start: Point, line_end: Point) -> float:
    numerator = abs(
        (line_end[1] - line_start[1]) * point[0]
        - (line_end[0] - line_start[0]) * point[1]
        + line_end[0] * line_start[1]
        - line_end[1] * line_start[0]
    )
    denominator = _distance(line_start, line_end)
    return numerator / denominator


def _minimal_enclosing_radius(p1: Point, p2: Point, p3: Point) -> float:
    sides = sorted((_distance(p1, p2), _distance(p1, p3), _distance(p2, p3)))
    a, b, c = sides
    a2 = a * a
    b2 = b * b
    c2 = c * c

    if realcompare(c2, a2 + b2) != "LT":
        return c / 2.0

    area = _triangle_area(p1, p2, p3)
    if realcompare(area, 0.0) == "EQ":
        return c / 2.0

    return (a * b * c) / (4.0 * area)


def _fits_in_circle(p1: Point, p2: Point, p3: Point, radius: float) -> bool:
    return realcompare(_minimal_enclosing_radius(p1, p2, p3), radius) != "GT"


def _quadrant(point: Point) -> int:
    x_coord, y_coord = point
    if realcompare(x_coord, 0.0) != "LT" and realcompare(y_coord, 0.0) != "LT":
        return 1
    if realcompare(x_coord, 0.0) == "LT" and realcompare(y_coord, 0.0) != "LT":
        return 2
    if realcompare(x_coord, 0.0) != "GT" and realcompare(y_coord, 0.0) == "LT":
        return 3
    return 4


def _lic1(points: Sequence[Point], length1: float) -> bool:
    return any(realcompare(_distance(points[i], points[i + 1]), length1) == "GT" for i in range(len(points) - 1))


def _lic2(points: Sequence[Point], radius1: float) -> bool:
    for i in range(len(points) - 2):
        if not _fits_in_circle(points[i], points[i + 1], points[i + 2], radius1):
            return True
    return False


def _lic3(points: Sequence[Point], epsilon: float) -> bool:
    lower = PI - epsilon
    upper = PI + epsilon
    for i in range(len(points) - 2):
        angle = _angle(points[i], points[i + 1], points[i + 2])
        if angle is None:
            continue
        if realcompare(angle, lower) == "LT" or realcompare(angle, upper) == "GT":
            return True
    return False


def _lic4(points: Sequence[Point], area1: float) -> bool:
    for i in range(len(points) - 2):
        if realcompare(_triangle_area(points[i], points[i + 1], points[i + 2]), area1) == "GT":
            return True
    return False


def _lic5(points: Sequence[Point], q_pts: int, quads: int) -> bool:
    for start in range(len(points) - q_pts + 1):
        if len({_quadrant(points[index]) for index in range(start, start + q_pts)}) > quads:
            return True
    return False


def _lic6(points: Sequence[Point]) -> bool:
    for i in range(len(points) - 1):
        if realcompare(points[i + 1][0] - points[i][0], 0.0) == "LT":
            return True
    return False


def _lic7(points: Sequence[Point], n_pts: int, dist: float) -> bool:
    if len(points) < 3:
        return False

    for start in range(len(points) - n_pts + 1):
        first = points[start]
        last = points[start + n_pts - 1]
        if _same_point(first, last):
            for index in range(start + 1, start + n_pts - 1):
                if realcompare(_distance(first, points[index]), dist) == "GT":
                    return True
            continue

        for index in range(start + 1, start + n_pts - 1):
            if realcompare(_distance_from_line(points[index], first, last), dist) == "GT":
                return True
    return False


def _lic8(points: Sequence[Point], k_pts: int, length1: float) -> bool:
    if len(points) < 3:
        return False

    gap = k_pts + 1
    for i in range(len(points) - gap):
        if realcompare(_distance(points[i], points[i + gap]), length1) == "GT":
            return True
    return False


def _lic9(points: Sequence[Point], a_pts: int, b_pts: int, radius1: float) -> bool:
    if len(points) < 5:
        return False

    second_offset = a_pts + 1
    third_offset = a_pts + b_pts + 2
    for i in range(len(points) - third_offset):
        if not _fits_in_circle(points[i], points[i + second_offset], points[i + third_offset], radius1):
            return True
    return False


def _lic10(points: Sequence[Point], c_pts: int, d_pts: int, epsilon: float) -> bool:
    if len(points) < 5:
        return False

    second_offset = c_pts + 1
    third_offset = c_pts + d_pts + 2
    lower = PI - epsilon
    upper = PI + epsilon
    for i in range(len(points) - third_offset):
        angle = _angle(points[i], points[i + second_offset], points[i + third_offset])
        if angle is None:
            continue
        if realcompare(angle, lower) == "LT" or realcompare(angle, upper) == "GT":
            return True
    return False


def _lic11(points: Sequence[Point], e_pts: int, f_pts: int, area1: float) -> bool:
    if len(points) < 5:
        return False

    second_offset = e_pts + 1
    third_offset = e_pts + f_pts + 2
    for i in range(len(points) - third_offset):
        if realcompare(_triangle_area(points[i], points[i + second_offset], points[i + third_offset]), area1) == "GT":
            return True
    return False


def _lic12(points: Sequence[Point], g_pts: int) -> bool:
    if len(points) < 3:
        return False

    gap = g_pts + 1
    for i in range(len(points) - gap):
        if realcompare(points[i + gap][0] - points[i][0], 0.0) == "LT":
            return True
    return False


def _lic13(points: Sequence[Point], k_pts: int, length1: float, length2: float) -> bool:
    if len(points) < 3:
        return False

    gap = k_pts + 1
    has_greater = False
    has_less = False
    for i in range(len(points) - gap):
        distance = _distance(points[i], points[i + gap])
        if realcompare(distance, length1) == "GT":
            has_greater = True
        if realcompare(distance, length2) == "LT":
            has_less = True
        if has_greater and has_less:
            return True
    return False


def _lic14(points: Sequence[Point], a_pts: int, b_pts: int, radius1: float, radius2: float) -> bool:
    if len(points) < 5:
        return False

    second_offset = a_pts + 1
    third_offset = a_pts + b_pts + 2
    has_outside = False
    has_inside = False
    for i in range(len(points) - third_offset):
        p1 = points[i]
        p2 = points[i + second_offset]
        p3 = points[i + third_offset]
        if not _fits_in_circle(p1, p2, p3, radius1):
            has_outside = True
        if _fits_in_circle(p1, p2, p3, radius2):
            has_inside = True
        if has_outside and has_inside:
            return True
    return False


def _lic15(points: Sequence[Point], e_pts: int, f_pts: int, area1: float, area2: float) -> bool:
    if len(points) < 5:
        return False

    second_offset = e_pts + 1
    third_offset = e_pts + f_pts + 2
    has_greater = False
    has_less = False
    for i in range(len(points) - third_offset):
        area = _triangle_area(points[i], points[i + second_offset], points[i + third_offset])
        if realcompare(area, area1) == "GT":
            has_greater = True
        if realcompare(area, area2) == "LT":
            has_less = True
        if has_greater and has_less:
            return True
    return False


def decide(
    numpoints: int,
    x: List[float],
    y: List[float],
    parameters: Dict[str, float | int],
    lcm: List[List[str]],
    pum_diag: List[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    points = [_point(i, x, y) for i in range(numpoints)]

    cmv = [
        _lic1(points, float(parameters["LENGTH1"])),
        _lic2(points, float(parameters["RADIUS1"])),
        _lic3(points, float(parameters["EPSILON"])),
        _lic4(points, float(parameters["AREA1"])),
        _lic5(points, int(parameters["Q_PTS"]), int(parameters["QUADS"])),
        _lic6(points),
        _lic7(points, int(parameters["N_PTS"]), float(parameters["DIST"])),
        _lic8(points, int(parameters["K_PTS"]), float(parameters["LENGTH1"])),
        _lic9(points, int(parameters["A_PTS"]), int(parameters["B_PTS"]), float(parameters["RADIUS1"])),
        _lic10(points, int(parameters["C_PTS"]), int(parameters["D_PTS"]), float(parameters["EPSILON"])),
        _lic11(points, int(parameters["E_PTS"]), int(parameters["F_PTS"]), float(parameters["AREA1"])),
        _lic12(points, int(parameters["G_PTS"])),
        _lic13(points, int(parameters["K_PTS"]), float(parameters["LENGTH1"]), float(parameters["LENGTH2"])),
        _lic14(
            points,
            int(parameters["A_PTS"]),
            int(parameters["B_PTS"]),
            float(parameters["RADIUS1"]),
            float(parameters["RADIUS2"]),
        ),
        _lic15(
            points,
            int(parameters["E_PTS"]),
            int(parameters["F_PTS"]),
            float(parameters["AREA1"]),
            float(parameters["AREA2"]),
        ),
    ]

    pum = [[False] * 15 for _ in range(15)]
    for i in range(15):
        pum[i][i] = bool(pum_diag[i])

    for i in range(15):
        for j in range(15):
            if i == j:
                continue
            connector = lcm[i][j]
            if connector == "NOTUSED":
                pum[i][j] = True
            elif connector == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            else:
                pum[i][j] = cmv[i] or cmv[j]

    fuv = [(not pum[i][i]) or all(pum[i]) for i in range(15)]
    launch = all(fuv)
    return cmv, pum, fuv, launch
